const progressFill = document.querySelector(".progress-fill");
const progressText = document.querySelector(".progress-text");

function escapeHTML(value) {
  return String(value ?? "").replace(/[&<>"']/g, (char) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#039;"
  })[char]);
}

function nl(value) {
  return escapeHTML(value).replace(/\n/g, "<br>");
}

function compact(value, max = 120) {
  const text = String(value || "").replace(/\s+/g, " ").trim();
  return text.length > max ? text.slice(0, max - 1) + "..." : text;
}

function classContent(item) {
  return customClassContent[item.code] || null;
}

function classTitle(item) {
  return classContent(item)?.title || item.topic;
}

function classSubtopic(item) {
  return classContent(item)?.subtopics || item.subtopics;
}

function pageFor(unit) {
  return units.find((entry) => entry.key === unit)?.page || "cierre.html";
}

function classHref(item) {
  return `${pageFor(item.unit)}?class=${item.code}&v=conta2-class5-impact`;
}

function matrixReturnHref(classNumber = new URLSearchParams(window.location.search).get("class")) {
  const normalized = classNumber ? String(classNumber).padStart(2, "0") : "";
  return normalized
    ? `index.html?v=matrix-return&focusClass=${encodeURIComponent(normalized)}#matriz`
    : "index.html#matriz";
}

function buildModule() {
  const layout = document.querySelector("[data-conta-module]");
  if (!layout) return;
  const requested = new URLSearchParams(window.location.search).get("class") || document.body.dataset.defaultClass || "01";
  const activeClass = classes.find((item) => item.code === requested.padStart(2, "0")) || classes[0];
  const unit = units.find((entry) => entry.key === activeClass.unit) || units[0];
  const moduleClasses = classes.filter((item) => item.unit === unit.key);
  const grouped = [];
  for (let i = 0; i < moduleClasses.length; i += 4) grouped.push(moduleClasses.slice(i, i + 4));

  document.title = `${unit.title} | Contabilidad II`;
  document.querySelector("[data-module-title]").textContent = unit.title;
  document.querySelector("[data-module-range]").textContent = `Semanas ${unit.startWeek}-${unit.endWeek} · Clases ${unit.startCode}-${unit.endCode}`;
  document.querySelector("[data-module-summary]").textContent = unit.objective;

  layout.innerHTML = `
    <section class="intro-card reveal objective-card is-visible">
      <div>
        <h2>${escapeHTML(unit.title)}</h2>
        <p>${escapeHTML(unit.objective)}</p>
      </div>
      <div class="objective-video video-empty">
        <strong>Planeacion NIIF</strong>
        <span>Clase 4 semanal con caso numerico integrador.</span>
      </div>
    </section>

    <section class="learning-panel reveal is-visible" style="--steps: ${grouped.length}">
      <div class="learning-head">
        <div>
          <h2>Linea de avance del modulo</h2>
          <p>Subcontenidos oficiales por semana, con desarrollo de clase y caso NIIF integrador.</p>
        </div>
        <div class="progress-text">0% de avance</div>
      </div>
      <div class="progress-track"><span class="progress-fill"></span></div>
      <div class="step-line">
        ${grouped.map((weekClasses) => renderStepGroup(weekClasses, activeClass)).join("")}
      </div>
      <section class="lesson-list">
        ${moduleClasses.map((item) => renderLessonCard(item, item.code === activeClass.code)).join("")}
      </section>
    </section>
  `;

  setActiveLesson(activeClass.code);
  renderInlineDevelopment(activeClass.code, false);
  updateProgress();
}

function renderStepGroup(weekClasses, activeClass) {
  const first = weekClasses[0];
  const weekCase = weeklyCases.find((item) => item.week === first.week);
  const active = weekClasses.some((item) => item.code === activeClass.code);
  return `
    <div class="step-filter-item ${active ? "active" : ""}" data-step-group="${first.week}">
      <div class="step-chip ${active ? "active" : ""}" data-step="${weekClasses[0].code}">Semana ${first.week}: ${escapeHTML(compact(weekCase?.weeklyMacroTopic || first.topic, 70))}</div>
      <div class="lesson-class-panel">
        <div class="lesson-class-head">
          <span>Clases asociadas</span>
          <strong>${weekClasses.length}</strong>
        </div>
        <div class="lesson-class-grid">
          ${weekClasses.map((item) => renderClassButton(item, item.code === activeClass.code)).join("")}
        </div>
      </div>
    </div>`;
}

function renderClassButton(item, active) {
  return `
    <button id="class-${item.code}" class="lesson-class-card ${active ? "preview-active" : ""}" type="button" data-class-slide="true" data-class-number="${item.code}">
      <span class="lesson-class-badge">Clase ${item.code}</span>
      <strong>${escapeHTML(classContent(item)?.shortTitle || classTitle(item))}</strong>
      <small>${escapeHTML(compact(classSubtopic(item), 110))}</small>
      <span class="lesson-class-cta">
        <span>Ver desarrollo</span>
        <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M15 3h6v6"></path><path d="M10 14 21 3"></path><path d="M21 14v5a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5"></path></svg>
      </span>
    </button>`;
}

function renderLessonCard(item, active) {
  return `
    <article class="lesson-card reveal is-visible ${active ? "active" : ""}" data-lesson="${item.code}">
      <div class="lesson-top">
        <div class="lesson-top-main">
          <span>Semana ${item.week} · Clase semanal ${item.weeklyClass}</span>
          <h3>${escapeHTML(classTitle(item))}</h3>
          <p>${escapeHTML(compact(classSubtopic(item), 180))}</p>
        </div>
        <button class="lesson-top-fullscreen" type="button" data-inline-class-fullscreen="${item.code}" aria-label="Agrandar contenido de la clase ${item.code}">
          <span>Agrandar contenido</span>
          <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M8 3H3v5"></path><path d="M16 3h5v5"></path><path d="M21 16v5h-5"></path><path d="M3 16v5h5"></path></svg>
        </button>
      </div>
    </article>`;
}

function renderInlineDevelopment(classCode, scroll = true) {
  const item = classes.find((entry) => entry.code === String(classCode).padStart(2, "0")) || classes[0];
  const lesson = document.querySelector(`.lesson-card[data-lesson="${CSS.escape(item.code)}"]`);
  if (!lesson) return;
  lesson.querySelector(".lesson-development")?.remove();
  const preview = document.createElement("div");
  preview.className = "lesson-development lesson-inline-development intro-inline-development";
  preview.innerHTML = `
    ${renderClassDeck(item)}
  `;
  lesson.appendChild(preview);
  if (scroll) document.querySelector(".learning-panel")?.scrollIntoView({ behavior: "smooth", block: "start" });
}

function renderClassDeck(item) {
  if (classContent(item)) return renderCustomClassDeck(item, classContent(item));
  const weekCase = weeklyCases.find((entry) => entry.week === item.week);
  return `
    <div class="class-master-deck accounting-deck">
      <section class="accounting-hero-panel">
        <div>
          <span class="class-section-label">${escapeHTML(item.unit)} · Clase ${item.code} · Semana ${item.week}</span>
          <h4>${escapeHTML(item.topic)}</h4>
          <p>${nl(item.subtopics)}</p>
        </div>
        <div class="accounting-statement-map" aria-label="Mapa NIIF de la clase">
          <span>NIIF</span>
          <strong>PYMES</strong>
          <em>Clase ${item.weeklyClass}</em>
        </div>
      </section>
      <section class="accounting-objective-panel">
        <span class="class-section-label">Competencia / objetivo</span>
        <h5>Lo que debe dominar el estudiante</h5>
        <p>${nl(item.objective)}</p>
      </section>
      <section class="accounting-niif-panel">
        <article>
          <span class="class-section-label">NIIF para PYMES</span>
          <h5>Norma vigente aplicada</h5>
          <p>${nl(item.niifPymes)}</p>
        </article>
        <article>
          <span class="class-section-label">Referencia NIIF completas</span>
          <h5>Puente normativo</h5>
          <p>${nl(item.fullNiif)}</p>
        </article>
      </section>
      <section class="accounting-process-panel">
        <span class="class-section-label">Estrategia didactica</span>
        <h5>Desarrollo de la clase</h5>
        <div class="accounting-process-grid">
          <article><strong>1</strong><span>Activar</span><p>${escapeHTML(compact(item.strategy, 100))}</p></article>
          <article><strong>2</strong><span>Aplicar</span><p>Resolver registros, clasificaciones, mediciones o revelaciones segun la norma.</p></article>
          <article><strong>3</strong><span>Integrar</span><p>Conectar la clase con el caso numerico semanal.</p></article>
        </div>
      </section>
      ${weekCase ? renderWeeklyCasePanel(weekCase, item) : ""}
      <section class="class-close-panel accounting-close-panel">
        <span class="class-section-label">Cierre</span>
        <h5>Pregunta de transferencia</h5>
        <p>¿Que cambia en los estados financieros si esta partida se reconoce, mide o revela incorrectamente?</p>
      </section>
    </div>`;
}

